use serde::Serialize;
use std::time::SystemTime;

/// Health status of the service
#[derive(Debug, Clone, Serialize, PartialEq, Eq)]
#[serde(rename_all = "lowercase")]
pub enum HealthStatus {
    /// Service is healthy and operational
    Healthy,
    /// Service is degraded but operational
    Degraded,
    /// Service is unhealthy
    Unhealthy,
}

/// Health check response structure
#[derive(Debug, Clone, Serialize)]
pub struct HealthResponse {
    /// Current health status
    pub status: HealthStatus,
    /// Service version
    pub version: String,
    /// Service uptime in seconds
    pub uptime_seconds: u64,
    /// Timestamp of the check
    pub timestamp: u64,
}

impl HealthResponse {
    /// Creates a new healthy response
    ///
    /// # Arguments
    ///
    /// * `version` - The service version string
    /// * `start_time` - The service start time
    ///
    /// # Returns
    ///
    /// A new HealthResponse with healthy status
    pub fn healthy(version: String, start_time: SystemTime) -> Self {
        let now = SystemTime::now();
        let uptime = now
            .duration_since(start_time)
            .unwrap_or_default()
            .as_secs();
        let timestamp = now
            .duration_since(SystemTime::UNIX_EPOCH)
            .unwrap_or_default()
            .as_secs();

        Self {
            status: HealthStatus::Healthy,
            version,
            uptime_seconds: uptime,
            timestamp,
        }
    }

    /// Creates a new degraded response
    pub fn degraded(version: String, start_time: SystemTime) -> Self {
        let mut response = Self::healthy(version, start_time);
        response.status = HealthStatus::Degraded;
        response
    }

    /// Creates a new unhealthy response
    pub fn unhealthy(version: String, start_time: SystemTime) -> Self {
        let mut response = Self::healthy(version, start_time);
        response.status = HealthStatus::Unhealthy;
        response
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_health_status_serialization() {
        let status = HealthStatus::Healthy;
        let json = serde_json::to_string(&status).unwrap();
        assert_eq!(json, r#""healthy""#);
    }

    #[test]
    fn test_health_response_creation() {
        let start_time = SystemTime::now();
        let response = HealthResponse::healthy("1.0.0".to_string(), start_time);

        assert_eq!(response.status, HealthStatus::Healthy);
        assert_eq!(response.version, "1.0.0");
        assert!(response.uptime_seconds >= 0);
    }
}
